const input = $('AI Agent').first().json;

// Mapeamos el arco narrativo para que n8n cree 4 ejecuciones independientes
return input.output.narrative_arc.map((scene, index) => {
  const step = index + 1;

  return {
    json: {
      image_id: `image_step${step}`,
      // Enviamos el objeto image_prompt completo convertido a String JSON
      image_prompt: JSON.stringify(scene.image_prompt),

      audio_id: `audio_step${step}`,
      // El prompt de audio suele ser el texto del Voice Over
      audio_prompt: scene.voice_over, 

      video_id: `video_step${step}`,
      // Enviamos el objeto video_prompt completo convertido a String JSON
      video_prompt: JSON.stringify(scene.video_prompt),
    }
  };
});

return items;
